import json
from datetime import datetime

def handler(*args, **kwargs):
    """转换上游数据格式"""
    upstream = kwargs.get("upstream", {})
    mapping = kwargs.get("mapping", {})
    result = {}
    for upstream_key, target_key in mapping.items():
        for source, value in upstream.items():
            if isinstance(value, dict) and upstream_key in value:
                result[target_key] = value[upstream_key]
    result["transformed_at"] = datetime.now().isoformat()
    return result
